import express, { type Request, type Response } from "express";

const app = express();
const port = 3000;

app.use(express.json());

app.get("/health", (req: Request, res: Response) => {
    res.status(200).json({ success: true });
});

app.listen(port, () => {
    console.log(`Server running on port ${port}`);
});

